/**
 * @name Zip Slip - ZipEntry name used in file construction without validation
 * @description Archive entry names used to construct file paths without checking for path traversal
 * @kind path-problem
 * @problem.severity error
 * @id java/zip-slip-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module ZipSlipConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // ZipEntry.getName() or ZipArchiveEntry.getName()
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      (
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.util.zip", "ZipEntry") or
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.apache.commons.compress.archivers.zip", "ZipArchiveEntry") or
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.apache.commons.compress.archivers", "ArchiveEntry")
      ) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // File constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // Paths.get()
    exists(MethodCall mc |
      mc.getMethod().hasName("get") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Path.resolve()
    exists(MethodCall mc |
      mc.getMethod().hasName("resolve") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.nio.file", "Path") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module ZipSlipFlow = TaintTracking::Global<ZipSlipConfig>;
import ZipSlipFlow::PathGraph

from ZipSlipFlow::PathNode source, ZipSlipFlow::PathNode sink
where ZipSlipFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential Zip Slip: archive entry name $@ flows to file system operation without path traversal check.", source.getNode(), "ZipEntry.getName()"

/**
 * @name Tar/Archive entry name flows to file creation - Zip Slip (TAR variant)
 * @description TarArchiveEntry or other archive entry names used to create files without path traversal check
 * @kind path-problem
 * @problem.severity error
 * @id java/tar-slip-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module TarSlipConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      (
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.apache.commons.compress.archivers.tar", "TarArchiveEntry") or
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.apache.commons.compress.archivers", "ArchiveEntry") or
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.util.zip", "ZipEntry")
      ) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // File constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // FileOutputStream
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileOutputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // FileInputStream
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileInputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
  }

  // Barrier: if canonical path check is performed, block flow
  predicate isBarrier(DataFlow::Node node) {
    exists(MethodCall mc |
      (mc.getMethod().hasName("getCanonicalPath") or mc.getMethod().hasName("getCanonicalFile")) and
      DataFlow::localFlow(node, DataFlow::exprNode(mc.getQualifier()))
    )
  }
}

module TarSlipFlow = TaintTracking::Global<TarSlipConfig>;
import TarSlipFlow::PathGraph

from TarSlipFlow::PathNode source, TarSlipFlow::PathNode sink
where TarSlipFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Archive entry name $@ flows to file operation without path traversal check.", source.getNode(), "archive entry getName()"

/**
 * @name Absolute path traversal via File construction from string concatenation
 * @description User or archive-derived path strings concatenated and used in file operations without normalization
 * @kind path-problem
 * @problem.severity error
 * @id java/absolute-path-traversal-concat
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-036
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module AbsPathConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Archive entry names
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      (
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.util.zip", "ZipEntry") or
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.apache.commons.compress.archivers", "ArchiveEntry")
      ) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // FileOutputStream construction
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileOutputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // BufferedOutputStream/PrintWriter/FileWriter from File
    exists(ClassInstanceExpr ce |
      (
        ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "BufferedOutputStream") or
        ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "PrintWriter") or
        ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileWriter") or
        ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "BufferedWriter")
      ) and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // mkdirs() or mkdir() called on a file constructed from the tainted path
    exists(MethodCall mc |
      (mc.getMethod().hasName("mkdirs") or mc.getMethod().hasName("mkdir")) and
      sink.asExpr() = mc.getQualifier()
    )
  }
}

module AbsPathFlow = TaintTracking::Global<AbsPathConfig>;
import AbsPathFlow::PathGraph

from AbsPathFlow::PathNode source, AbsPathFlow::PathNode sink
where AbsPathFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Archive entry name $@ reaches file write/mkdir operation without path traversal protection.", source.getNode(), "archive entry getName()"

/**
 * @name Dependency file path flows to ProcessBuilder in AssemblyAnalyzer
 * @description Scanned dependency file paths used in external process execution without validation
 * @kind path-problem
 * @problem.severity high
 * @id java/assembly-analyzer-dependency-path
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-073
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module AssemblyConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Dependency.getActualFilePath(), getFilePath(), getFileName() - these are the scanned files
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("getActualFilePath") or
        mc.getMethod().hasName("getFilePath") or
        mc.getMethod().hasName("getFileName") or
        mc.getMethod().hasName("getAbsolutePath") or
        mc.getMethod().hasName("getCanonicalPath")
      ) and
      (
        mc.getMethod().getDeclaringType().hasQualifiedName("org.owasp.dependencycheck.dependency", "Dependency") or
        mc.getMethod().getDeclaringType().hasQualifiedName("java.io", "File")
      ) and
      mc.getEnclosingCallable().getDeclaringType().getName().matches("%Assembly%") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // ProcessBuilder constructor arguments
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.lang", "ProcessBuilder") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // List.add() for process builder args
    exists(MethodCall mc |
      (mc.getMethod().hasName("add") or mc.getMethod().hasName("set")) and
      mc.getEnclosingCallable().getDeclaringType().getName().matches("%Assembly%") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module AssemblyFlow = TaintTracking::Global<AssemblyConfig>;
import AssemblyFlow::PathGraph

from AssemblyFlow::PathNode source, AssemblyFlow::PathNode sink
where AssemblyFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Dependency file path $@ flows to external process arguments in AssemblyAnalyzer.", source.getNode(), "dependency file path"

/**
 * @name Suppression/Hint file loaded from user-controlled URL or path without validation
 * @description User-specified suppression or hint file URLs/paths loaded without path traversal validation
 * @kind path-problem
 * @problem.severity high
 * @id java/suppression-hint-file-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-073
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module SuppressionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Settings.getString() - user-configurable settings
    exists(MethodCall mc |
      mc.getMethod().hasName("getString") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.owasp.dependencycheck.utils", "Settings") and
      source.asExpr() = mc
    )
    or
    // getSuppressionFile() or getHintsFile() - these return user-provided paths
    exists(MethodCall mc |
      (
        mc.getMethod().getName().matches("%uppression%") or
        mc.getMethod().getName().matches("%int%") or
        mc.getMethod().getName().matches("%File%") or
        mc.getMethod().getName().matches("%Path%")
      ) and
      mc.getMethod().getDeclaringType().getPackage().getName().matches("org.owasp.dependencycheck%") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // URL constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.net", "URL") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // File constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // openStream() or openConnection()
    exists(MethodCall mc |
      (mc.getMethod().hasName("openStream") or mc.getMethod().hasName("openConnection")) and
      sink.asExpr() = mc.getQualifier()
    )
  }
}

module SuppressionFlow = TaintTracking::Global<SuppressionConfig>;
import SuppressionFlow::PathGraph

from SuppressionFlow::PathNode source, SuppressionFlow::PathNode sink
where SuppressionFlow::flowPath(source, sink) and
  (
    sink.getNode().getEnclosingCallable().getDeclaringType().getName().matches("%Suppression%") or
    sink.getNode().getEnclosingCallable().getDeclaringType().getName().matches("%Hint%") or
    sink.getNode().getEnclosingCallable().getDeclaringType().getName().matches("%Parser%") or
    sink.getNode().getEnclosingCallable().getDeclaringType().getName().matches("%Abstract%")
  )
select sink.getNode(), source, sink, "User-controlled path/URL $@ flows to file/URL operation in suppression/hint file loading.", source.getNode(), "user-controlled settings value"
